/**
 * Loads data from Trello chunk by chunk
 * @param scope
 * @param permission
 * @param chunkSize
 * @param key
 * @returns {Promise<[]>}
 */
const loadData = async ({scope = 'board', permission = 'shared', chunkSize = 100, key}) => {
    const cardData = [];

    let i = 0;
    let cardSlice = [];
    do {
        cardSlice = await window.TrelloPowerUp.iframe().get(scope, permission, `${key + i.toString()}`);
        cardData.push(...cardSlice);
        i += chunkSize;
    } while (cardSlice.length === chunkSize);

    return cardData;
}

$(async function () {
    let t = window.TrelloPowerUp.iframe();
    let pivotData = await t.get('board', 'shared', 'pivotData');

    if (!pivotData) {
        pivotData = {
            rows: ['Members'],
            cols: ['List index', 'List'],
            aggregatorName: 'Count',
            rendererName: 'Table'
        };
    }

    if (pivotData.hasOwnProperty('aggregators')) {
        delete pivotData.aggregators;
    }
    if (pivotData.hasOwnProperty('renderers')) {
        delete pivotData.renderers;
    }

    pivotData.onRefresh = async (pivotData) => {
        await t.set('board', 'shared', 'pivotData', pivotData);
        $('.pvtTable, table').css('width', 'auto');
    };

    const cardData = await loadData({key: 'cardData'});

    $('#output').pivotUI(cardData, pivotData);
    $('.pvtTable, table').css('width', 'auto');
});
